import { cva } from 'class-variance-authority'

export const copyToClipboardVariants = cva(
    [
        'inline-flex items-center justify-center gap-2 font-black tracking-wide',
        'border-3 border-brutal transition-all duration-150',
        'h-11 px-5 rounded-brutal shadow-brutal select-none cursor-pointer',
        'disabled:opacity-50 disabled:pointer-events-none',
    ],
    {
        variants: {
            state: {
                idle: 'bg-brutal-bg text-brutal-fg hover:bg-brutal-muted hover:-translate-x-0.5 hover:-translate-y-0.5 hover:shadow-brutal-lg active:translate-y-[var(--brutal-pressed-offset,2px)] active:shadow-none',
                copied: 'bg-brutal-success text-brutal-fg translate-y-[var(--brutal-pressed-offset,2px)] shadow-none',
            },
        },
        defaultVariants: {
            state: 'idle',
        },
    }
)

import { ref, onUnmounted, toValue, type MaybeRefOrGetter } from 'vue'

const DEFAULT_COPIED_DURATION = 2000

export function useClipboard(options: { duration?: MaybeRefOrGetter<number> } = {}) {
    const copied = ref(false)
    const isSupported = ref(typeof navigator !== 'undefined' && !!navigator.clipboard?.writeText)

    let timeoutId: ReturnType<typeof setTimeout> | null = null

    onUnmounted(() => {
        if (timeoutId) clearTimeout(timeoutId)
    })

    async function copy(text: string) {
        if (!isSupported.value) return false

        try {
            await navigator.clipboard.writeText(text)
            copied.value = true

            if (timeoutId) clearTimeout(timeoutId)
            const duration = toValue(options.duration) ?? DEFAULT_COPIED_DURATION
            timeoutId = window.setTimeout(() => {
                copied.value = false
            }, duration)

            return true
        } catch (err) {
            console.error('Failed to copy text: ', err)
            return false
        }
    }

    return {
        copy,
        copied,
        isSupported,
    }
}

import { type ComputedRef, type InjectionKey, type MaybeRef, computed, inject, provide, unref } from 'vue'
import { zhCN } from '../locales/zh-CN'
import type { Locale } from '../locales/types'

export const LOCALE_INJECTION_KEY: InjectionKey<MaybeRef<Locale>> = Symbol('brutx-ui-locale')

export type TranslateFunction = (path: string, params?: Record<string, string | number>) => string

export function provideLocale(locale: MaybeRef<Locale>) {
    provide(LOCALE_INJECTION_KEY, locale)
}

function resolveByPath(obj: unknown, path: string): string | undefined {
    const keys = path.split('.')
    let result: unknown = obj
    for (const key of keys) {
        if (result == null || typeof result !== 'object') return undefined
        result = (result as Record<string, unknown>)[key]
    }
    return typeof result === 'string' ? result : undefined
}

function interpolate(template: string, params?: Record<string, string | number>): string {
    if (!params) return template
    return Object.entries(params).reduce(
        (str, [k, v]) => str.split(`{${k}}`).join(String(v)),
        template,
    )
}

export function useLocale(): { locale: ComputedRef<Locale>; t: TranslateFunction } {
    const injected = inject<MaybeRef<Locale> | undefined>(LOCALE_INJECTION_KEY, undefined)

    const locale = computed<Locale>(() => {
        const resolved = injected ? unref(injected) : undefined
        return resolved ?? zhCN
    })

    function t(path: string, params?: Record<string, string | number>): string {
        const currentVal = resolveByPath(locale.value, path)
        if (currentVal !== undefined) return interpolate(currentVal, params)

        const fallbackVal = resolveByPath(zhCN, path)
        if (fallbackVal !== undefined) return interpolate(fallbackVal, params)

        return path
    }

    return { locale, t }
}
